#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,m,k,s,p,q,x,y,dis[MAXN];
bool c[MAXN],d[MAXN],vis[MAXN];
vector<PII> g[MAXN];
vector<PII> e;
void dij(int u)
{
    FOR(i,1,n)dis[i]=llinf,vis[i]=0;
    dis[u]=0;
    priority_queue<PII,vector<PII>,greater<PII>> q;
    q.push(mk(0,u));
    wh(!q.empty())
    {
        int now=q.top().snd;q.pop();
        if(vis[now])continue;
        vis[now]=1;
        FOI(ed,g[now])
        {
            int v=ed.fst,w=ed.snd;
            if(dis[v]>dis[now]+w)
            {
                dis[v]=dis[now]+w;
                q.push(mk(dis[v],v));
            }
        }
    }
}

signed main(void)
{
    n=read(),m=read(),k=read(),s=read(),p=read(),q=read();
    FOR(i,1,k)
    {
        x=read();
        c[x]=1;
    }
    FOR(i,1,m)
    {
        x=read(),y=read();
        e.pb(mk(x,y));
        if(c[x]&&c[y])continue;
        int u=c[x]?0:x;
        int v=c[y]?0:y;
        g[u].pb(mk(v,1));
        g[v].pb(mk(u,1));
    }
    dij(0);
    FOR(i,1,n)if(dis[i]<=s)d[i]=1;
    FOR(i,0,n)g[i].clear();
    FOI(ed,e)
    {
        x=ed.fst,y=ed.snd;
        if(c[x]||c[y])continue;
        int w1=(y==n)?0:(d[y]?q:p);
        int w2=(x==n)?0:(d[x]?q:p);
        g[x].pb(mk(y,w1));
        g[y].pb(mk(x,w2));
    }
    dij(1);
    write(dis[n]);
    return false;
}
